SELECT COUNT(*) AS total_confirmed_orders
FROM sale_order
WHERE state IN ('sale', 'done');

SELECT COUNT(*) AS total_posted_journal_entries
FROM account_move
WHERE state = 'posted';

SELECT COUNT(DISTINCT so.partner_id) AS unique_customers
FROM sale_order so
WHERE so.state IN ('sale', 'done');

SELECT so.id, so.name AS order_name, rp.name AS customer_name
FROM sale_order so
JOIN res_partner rp ON so.partner_id = rp.id;

WITH
  q_demand AS (
    SELECT rp.id AS customer_id, rp.name AS customer_name, SUM(so.amount_total) AS total_sales_amount FROM sale_order AS so JOIN res_partner AS rp ON rp.id = so.partner_id WHERE so.state IN ('sale', 'done') GROUP BY rp.id, rp.name ORDER BY total_sales_amount DESC
  ),
  q_finance AS (
    SELECT rp.name AS customer, SUM(aml.credit - aml.debit) AS total_revenue FROM account_move_line AS aml JOIN account_move AS am ON am.id = aml.move_id JOIN account_account AS aa ON aa.id = aml.account_id JOIN res_partner AS rp ON rp.id = am.partner_id WHERE aa.account_type = 'income' AND am.state = 'posted' AND am.move_type = 'out_invoice' GROUP BY rp.name ORDER BY total_revenue DESC
  )
SELECT q_demand.customer_id, q_demand.customer_name, q_demand.total_sales_amount, q_finance.customer, q_finance.total_revenue
FROM q_demand CROSS JOIN q_finance;

SELECT po.name AS order_reference, rp.name AS supplier_name
FROM purchase_order po
JOIN res_partner rp ON po.partner_id = rp.id;

WITH
  q_inventory AS (
    SELECT sm.picking_id, sm.product_id, pt.name ->> 'en_US' AS product_name, sm.product_qty, sm.quantity AS done_qty, lsrc.complete_name AS source_location, ldst.complete_name AS destination_location, sm.state, sm.date FROM stock_move AS sm JOIN product_product AS pp ON pp.id = sm.product_id JOIN product_template AS pt ON pt.id = pp.product_tmpl_id JOIN stock_location AS lsrc ON lsrc.id = sm.location_id JOIN stock_location AS ldst ON ldst.id = sm.location_dest_id WHERE NOT sm.picking_id IS NULL ORDER BY sm.picking_id, sm.id
  ),
  q_logistics AS (
    SELECT dc.name AS carrier, COUNT(sp.id) AS picking_count FROM stock_picking AS sp JOIN delivery_carrier AS dc ON dc.id = sp.carrier_id GROUP BY dc.name ORDER BY picking_count DESC
  )
SELECT q_inventory.picking_id, q_inventory.product_id, q_inventory.product_name, q_inventory.product_qty, q_inventory.done_qty, q_inventory.source_location, q_inventory.destination_location, q_inventory.state, q_inventory.date, q_logistics.carrier, q_logistics.picking_count
FROM q_inventory CROSS JOIN q_logistics;

WITH
  q_finance AS (
    SELECT SUM(aml.credit - aml.debit) AS total_revenue FROM account_move_line AS aml JOIN account_account AS aa ON aa.id = aml.account_id JOIN account_move AS am ON am.id = aml.move_id WHERE aa.account_type = 'income' AND am.state = 'posted' AND am.date >= CAST('2026-01-01' AS DATE) AND am.date < CAST('2027-01-01' AS DATE)
  ),
  q_demand AS (
    SELECT rp.id AS customer_id, rp.name AS customer_name, COUNT(so.id) AS order_count FROM res_partner AS rp JOIN sale_order AS so ON so.partner_id = rp.id WHERE so.state IN ('sale', 'done') AND so.date_order >= CAST('2026-01-01' AS DATE) AND so.date_order < CAST('2027-01-01' AS DATE) GROUP BY rp.id, rp.name ORDER BY order_count DESC
  )
SELECT q_finance.total_revenue, q_demand.customer_id, q_demand.customer_name, q_demand.order_count
FROM q_finance CROSS JOIN q_demand;

WITH
  q_inventory AS (
    SELECT pp.id AS product_id, pt.name ->> 'en_US' AS product_name, pt.default_code AS internal_reference, SUM(sq.quantity) AS on_hand_quantity FROM stock_quant AS sq JOIN product_product AS pp ON pp.id = sq.product_id JOIN product_template AS pt ON pt.id = pp.product_tmpl_id JOIN stock_location AS sl ON sl.id = sq.location_id WHERE sl.usage = 'internal' GROUP BY pp.id, pt.name, pt.default_code ORDER BY on_hand_quantity DESC
  ),
  q_demand AS (
    SELECT pt.name ->> 'en_US' AS product, SUM(sol.product_uom_qty) AS total_units_sold FROM sale_order_line AS sol JOIN sale_order AS so ON so.id = sol.order_id JOIN product_product AS pp ON pp.id = sol.product_id JOIN product_template AS pt ON pt.id = pp.product_tmpl_id WHERE so.state IN ('sale', 'done') AND so.date_order >= CAST('2026-01-01' AS DATE) AND so.date_order < CAST('2027-01-01' AS DATE) GROUP BY pt.id, pt.name ORDER BY total_units_sold DESC
  )
SELECT q_inventory.product_id, q_inventory.product_name, q_inventory.internal_reference, q_inventory.on_hand_quantity, q_demand.product, q_demand.total_units_sold
FROM q_inventory CROSS JOIN q_demand;

WITH
  q_inventory AS (
    SELECT pp.id AS product_id, pt.default_code AS internal_reference, pt.name ->> 'en_US' AS product_name, SUM(sq.quantity) AS on_hand_quantity, u.name ->> 'en_US' AS uom FROM stock_quant AS sq JOIN product_product AS pp ON pp.id = sq.product_id JOIN product_template AS pt ON pt.id = pp.product_tmpl_id JOIN stock_location AS sl ON sl.id = sq.location_id JOIN uom_uom AS u ON u.id = pt.uom_id WHERE sl.usage = 'internal' GROUP BY pp.id, pt.default_code, pt.name, u.name ORDER BY on_hand_quantity DESC
  ),
  q_demand AS (
    SELECT pt.name ->> 'en_US' AS product, AVG(monthly_qty) AS avg_monthly_demand FROM (SELECT sol.product_id, DATE_TRUNC('MONTH', so.date_order) AS month, SUM(sol.product_uom_qty) AS monthly_qty FROM sale_order_line AS sol JOIN sale_order AS so ON so.id = sol.order_id WHERE so.state IN ('sale', 'done') GROUP BY sol.product_id, DATE_TRUNC('MONTH', so.date_order)) AS monthly_demand JOIN product_product AS pp ON pp.id = monthly_demand.product_id JOIN product_template AS pt ON pt.id = pp.product_tmpl_id GROUP BY pt.id, pt.name ORDER BY avg_monthly_demand DESC
  )
SELECT q_inventory.product_id, q_inventory.internal_reference, q_inventory.product_name, q_inventory.on_hand_quantity, q_inventory.uom, q_demand.product, q_demand.avg_monthly_demand
FROM q_inventory CROSS JOIN q_demand;

WITH
  q_inventory AS (
    SELECT pt.name ->> 'en_US' AS product, pp.id AS product_id, COALESCE(SUM(svl_out.value * -1), 0) AS annual_cogs, CASE WHEN COUNT(svl_all.id) > 0 THEN (SUM(svl_all.quantity * svl_all.unit_cost) / NULLIF(COUNT(DISTINCT svl_all.id), 0)) ELSE 0 END AS avg_inventory_value, CASE WHEN AVG(ABS(svl_all.unit_cost * svl_all.quantity)) > 0 THEN (COALESCE(SUM(CASE WHEN svl_out.quantity < 0 THEN svl_out.value * -1 ELSE 0 END), 0)) / NULLIF((SELECT AVG(sub_val.total_value) FROM (SELECT DATE_TRUNC('MONTH', svl2.create_date) AS month, SUM(svl2.quantity * svl2.unit_cost) AS total_value FROM stock_valuation_layer AS svl2 WHERE svl2.product_id = pp.id GROUP BY DATE_TRUNC('MONTH', svl2.create_date)) AS sub_val), 0) ELSE NULL END AS inventory_turnover_rate FROM product_product AS pp JOIN product_template AS pt ON pt.id = pp.product_tmpl_id LEFT JOIN stock_valuation_layer AS svl_all ON svl_all.product_id = pp.id AND svl_all.create_date >= CURRENT_TIMESTAMP - INTERVAL '1 YEAR' LEFT JOIN stock_valuation_layer AS svl_out ON svl_out.product_id = pp.id AND svl_out.quantity < 0 AND svl_out.create_date >= CURRENT_TIMESTAMP - INTERVAL '1 YEAR' GROUP BY pp.id, pt.name HAVING NOT SUM(svl_all.quantity) IS NULL ORDER BY inventory_turnover_rate DESC NULLS LAST
  ),
  q_finance AS (
    SELECT pp.id AS product_id, COALESCE(CAST(pt.name AS JSON) ->> 'en_US', CAST(pt.name AS TEXT)) AS product_name, SUM(aml.credit - aml.debit) AS revenue FROM account_move_line AS aml JOIN account_move AS am ON am.id = aml.move_id JOIN account_account AS aa ON aa.id = aml.account_id JOIN product_product AS pp ON pp.id = aml.product_id JOIN product_template AS pt ON pt.id = pp.product_tmpl_id WHERE aa.account_type = 'income' AND am.state = 'posted' AND NOT aml.product_id IS NULL GROUP BY pp.id, pt.name ORDER BY revenue DESC
  )
SELECT q_inventory.product, q_inventory.product_id, q_inventory.annual_cogs, q_inventory.avg_inventory_value, q_inventory.inventory_turnover_rate, q_finance.product_id AS q_finance_product_id, q_finance.product_name, q_finance.revenue
FROM q_inventory CROSS JOIN q_finance;

WITH
  q_finance AS (
    SELECT rp.name AS customer, SUM(aml.credit - aml.debit) AS total_revenue FROM account_move_line AS aml JOIN account_move AS am ON am.id = aml.move_id JOIN account_account AS aa ON aa.id = aml.account_id JOIN res_partner AS rp ON rp.id = am.partner_id WHERE aa.account_type = 'income' AND am.state = 'posted' AND am.move_type IN ('out_invoice', 'out_refund') AND am.date >= CAST('2026-01-01' AS DATE) AND am.date < CAST('2027-01-01' AS DATE) GROUP BY rp.name ORDER BY total_revenue DESC
  ),
  q_demand AS (
    SELECT rp.id AS customer_id, rp.name AS customer_name, COUNT(so.id) AS order_count, SUM(so.amount_total) AS total_revenue, AVG(so.amount_total) AS avg_order_value FROM sale_order AS so JOIN res_partner AS rp ON rp.id = so.partner_id WHERE so.state IN ('sale', 'done') AND so.date_order >= CAST('2026-01-01' AS DATE) AND so.date_order < CAST('2027-01-01' AS DATE) GROUP BY rp.id, rp.name ORDER BY total_revenue DESC LIMIT 20
  )
SELECT q_finance.customer, q_finance.total_revenue, q_demand.customer_id, q_demand.customer_name, q_demand.order_count, q_demand.total_revenue AS q_demand_total_revenue, q_demand.avg_order_value
FROM q_finance CROSS JOIN q_demand;

SELECT *
FROM stock_quant
WHERE quantity > 10;

SELECT *
FROM purchase_order
WHERE EXTRACT(YEAR FROM date_order) = EXTRACT(YEAR FROM CURRENT_DATE);

SELECT *
FROM purchase_order
WHERE state = 'purchase';

WITH
  q_finance AS (
    SELECT SUM(aml.credit - aml.debit) AS total_revenue FROM account_move_line AS aml JOIN account_account AS aa ON aa.id = aml.account_id JOIN account_move AS am ON am.id = aml.move_id WHERE aa.account_type = 'income' AND am.state = 'posted' AND NOT aml.product_id IS NULL AND am.date >= CAST('2026-01-01' AS DATE) AND am.date < CAST('2027-01-01' AS DATE)
  ),
  q_demand AS (
    SELECT so.name AS order_reference, rp.name AS customer, pt.name ->> 'en_US' AS product, sol.product_uom_qty AS quantity, sol.price_unit AS unit_price, sol.price_subtotal AS subtotal, so.amount_total AS order_total, so.date_order, so.state FROM sale_order AS so JOIN res_partner AS rp ON rp.id = so.partner_id JOIN sale_order_line AS sol ON sol.order_id = so.id JOIN product_product AS pp ON pp.id = sol.product_id JOIN product_template AS pt ON pt.id = pp.product_tmpl_id WHERE so.state IN ('sale', 'done') AND so.date_order >= CAST('2026-01-01' AS DATE) AND so.date_order < CAST('2027-01-01' AS DATE) ORDER BY so.date_order DESC
  )
SELECT q_finance.total_revenue, q_demand.order_reference, q_demand.customer, q_demand.product, q_demand.quantity, q_demand.unit_price, q_demand.subtotal, q_demand.order_total, q_demand.date_order, q_demand.state
FROM q_finance CROSS JOIN q_demand;
